/**
 * Build-time script that reads Firebase config from .env.local
 * and writes it to public/admin/report/firebase-config.js
 *
 * The generated file is listed in .gitignore — it is never committed.
 * Cloudflare Pages runs `next build` which calls `next build`,
 * so we hook into the prebuild phase.
 */

const fs = require("fs");
const path = require("path");

const envPath = path.resolve(__dirname, "..", ".env.local");
const outDir = path.resolve(__dirname, "..", "public", "admin", "report");
const outPath = path.join(outDir, "firebase-config.js");

// Read .env.local
let envContent = "";
try {
  envContent = fs.readFileSync(envPath, "utf-8");
} catch {
  console.warn(
    "⚠ .env.local not found — firebase-config.js will be empty (report page will fail gracefully)."
  );
}

const lines = envContent.split("\n").filter(Boolean);
const env = {};
for (const line of lines) {
  const eqIdx = line.indexOf("=");
  if (eqIdx === -1) continue;
  const key = line.slice(0, eqIdx).trim();
  const val = line.slice(eqIdx + 1).trim();
  if (key && val) env[key] = val;
}

const config = {
  apiKey: env.NEXT_PUBLIC_FIREBASE_API_KEY || "",
  authDomain: env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN || "",
  projectId: env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || "",
  storageBucket: env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID || "",
  appId: env.NEXT_PUBLIC_FIREBASE_APP_ID || "",
};

fs.mkdirSync(outDir, { recursive: true });
fs.writeFileSync(
  outPath,
  `// Auto-generated by scripts/generate-firebase-config.js — DO NOT COMMIT
// Generated at: ${new Date().toISOString()}
self.__FIREBASE_CONFIG__ = ${JSON.stringify(config, null, 2)};
`
);

console.log("✓ Generated public/admin/report/firebase-config.js");